1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type Damage = {
9	  itemType: string;
10	  amount: number;
11	};
12	
13	export type Incident = {
14	  cause: string;
15	  damages: Damage[];
16	};
17	
18	export type Step = {
19	  op: string;
20	  items?: Item[];
21	  policy?: number;
22	  incident?: Incident;
23	};
24	
25	export type Scenario = {
26	  customer: { yearsWithMHPCO: number };
27	  steps: Step[];
28	};
29	
30	export type QuoteResult = { premium: number };
31	export type ClaimResult = { payout: number; remainingCap: number };
32	export type StepResult = QuoteResult | ClaimResult;
33	
34	export type ScenarioResult = {
35	  results: StepResult[];
36	};
37	
38	const PROCESSING_FEE = 5;
39	const FIRST_INSURANCE_SURCHARGE = 0.1;
40	const LOYALTY_DISCOUNT = 0.2;
41	const LOYALTY_THRESHOLD_YEARS = 2;
42	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
43	const CURSED_SURCHARGE = 0.5;
44	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
45	const HIGH_ENCHANTMENT_THRESHOLD = 5;
46	const DEDUCTIBLE_PER_DAMAGE = 100;
47	const CAP_MULTIPLIER = 2;
48	
49	const ITEM_BASE_PREMIUM: Record<string, number> = {
50	  sword: 100,
51	  rune: 25,
52	  moonstone: 25,
53	};
54	
55	const ITEM_INSURANCE_VALUE: Record<string, number> = {
56	  sword: 1000,
57	};
58	
59	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
60	const COMPONENT_BLOCK_SIZE = 3;
61	const COMPONENT_BLOCK_PREMIUM = 60;
62	
63	const groupCountsByType = (items: Item[]): Map<string, number> => {
64	  const counts = new Map<string, number>();
65	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
66	  return counts;
67	};
68	
69	const basePremiumForGroup = (type: string, count: number): number => {
70	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
71	  return count * ITEM_BASE_PREMIUM[type];
72	};
73	
74	const sumBasePremium = (counts: Map<string, number>): number => {
75	  let total = 0;
76	  for (const [type, count] of counts) total += basePremiumForGroup(type, count);
77	  return total;
78	};
79	
80	const isHighlyEnchanted = (item: Item): boolean =>
81	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
82	
83	const surchargeRateForItem = (item: Item): number =>
84	  (item.cursed ? CURSED_SURCHARGE : 0) +
85	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
86	
87	const surchargeForItem = (item: Item): number =>
88	  ITEM_BASE_PREMIUM[item.type] * surchargeRateForItem(item);
89	
90	const itemSurcharges = (items: Item[]): number =>
91	  items.reduce((total, item) => total + surchargeForItem(item), 0);
92	
93	const calculatePremium = (
94	  items: Item[],
95	  yearsWithMHPCO: number,
96	  isFollowUpContract: boolean,
97	): number => {
98	  const base = sumBasePremium(groupCountsByType(items));
99	  const surcharges = itemSurcharges(items);
100	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE;
101	  const loyaltyDiscount =
102	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT : 0;
103	  const followUpDiscount = isFollowUpContract ? base * FOLLOWUP_CONTRACT_DISCOUNT : 0;
104	  return Math.ceil(
105	    base + surcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
106	  );
107	};
108	
109	type Policy = {
110	  items: Item[];
111	  remainingCap: number;
112	};
113	
114	const insuranceSum = (items: Item[]): number =>
115	  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);
116	
117	const payoutForDamage = (damage: Damage): number =>
118	  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);
119	
120	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
121	  const grossPayout = incident.damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
122	  const payout = Math.floor(Math.min(grossPayout, policy.remainingCap));
123	  policy.remainingCap -= payout;
124	  return { payout, remainingCap: policy.remainingCap };
125	};
126	
127	export const runScenario = (scenario: Scenario): ScenarioResult => {
128	  const policies: Policy[] = [];
129	  let quoteCount = 0;
130	  const results: StepResult[] = scenario.steps.map((step) => {
131	    if (step.op === "quote") {
132	      const items = step.items ?? [];
133	      const isFollowUpContract = quoteCount >= 1;
134	      quoteCount += 1;
135	      policies.push({ items, remainingCap: insuranceSum(items) * CAP_MULTIPLIER });
136	      return {
137	        premium: calculatePremium(items, scenario.customer.yearsWithMHPCO, isFollowUpContract),
138	      };
139	    }
140	    const policy = policies[step.policy as number];
141	    return processClaim(policy, step.incident as Incident);
142	  });
143	  return { results };
144	};
